<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Falling Sand Cellular Automata</title>
    <style>
        body {
            font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
            background-color: #1e1e2f; /* Dark background */
            color: #e0e0e0;
            display: flex;
            flex-direction: column;
            align-items: center;
            padding: 20px;
        }

        h1 {
            color: #8c9eff;
            margin-bottom: 30px;
        }

        #controls {
            display: flex;
            flex-wrap: wrap;
            gap: 15px;
            justify-content: center;
            margin-bottom: 20px;
            padding: 15px;
            background-color: #2a2a40;
            border-radius: 8px;
            box-shadow: 0 4px 10px rgba(0, 0, 0, 0.3);
        }

        /* Material Selector Buttons */
        .material-selector {
            display: flex;
            gap: 10px;
            margin-right: 20px;
        }

        button {
            padding: 10px 15px;
            border: none;
            border-radius: 6px;
            cursor: pointer;
            font-weight: bold;
            transition: background-color 0.2s, transform 0.1s;
            box-shadow: 0 3px #1a1a25;
        }

        button:active {
            transform: translateY(2px);
            box-shadow: 0 1px #1a1a25;
        }

        /* Material specific styling */
        #mat-sand { background-color: #d6893c; color: white; }
        #mat-water { background-color: #4fa6ff; color: white; }
        #mat-wall { background-color: #5a5a70; color: white; }
        #mat-acid { background-color: #c93e2d; color: white; }
        #mat-empty { background-color: #444; color: #aaa; }

        /* Clear Button */
        #clear {
            background-color: #a03535;
            color: white;
            margin-left: 20px;
        }

        /* Canvas Area */
        #sand-container {
            border: 4px solid #8c9eff;
            box-shadow: 0 10px 20px rgba(0, 0, 0, 0.5);
            background-color: #0d0d1a; /* Dark internal background */
        }

        #sand {
            display: block;
        }
    </style>
</head>
<body>

    <h1>Falling Sand Sandbox</h1>

    <div id="controls">
        <div class="material-selector">
            <button id="mat-sand" data-material="sand">Sand</button>
            <button id="mat-water" data-material="water">Water</button>
            <button id="mat-wall" data-material="wall">Wall</button>
            <button id="mat-acid" data-material="acid">Acid</button>
            <button id="mat-empty" data-material="empty">Eraser</button>
        </div>
        <button id="clear">Clear Grid</button>
    </div>

    <div id="sand-container">
        <canvas id="sand" width="600" height="480"></canvas>
    </div>

    <script>
        // --- Global Constants and State ---
        const CANVAS_SIZE = 400; // Minimum required size for the canvas drawing area (CSS pixels)
        const GRID_W = 80;       // Grid width in cells
        const GRID_H = 80;       // Grid height in cells

        const MATERIALS = {
            'empty': { color: '#1a1a25', density: 0, name: 'empty' },
            'sand':  { color: '#d6893c', density: 1, name: 'sand' },
            'water': { color: '#4fa6ff', density: 1, name: 'water' },
            'wall':  { color: '#5a5a70', density: 2, name: 'wall' },
            'acid':  { color: '#c93e2d', density: 1, name: 'acid' }
        };

        // --- Simulation State ---
        let grid = [];
        let currentMaterial = 'sand'; // Default material for painting

        // --- DOM Elements ---
        const canvasElement = document.getElementById('sand');
        const ctx = canvasElement.getContext('2d');
        const containerWidth = 600; // CSS width used in HTML/CSS
        const cellPixelSize = Math.floor(Math.min(containerWidth / GRID_W, CANVAS_SIZE / GRID_W));

        // Adjust canvas drawing size to match the calculated pixel size for consistency
        canvasElement.width = GRID_W * cellPixelSize;
        canvasElement.height = GRID_H * cellPixelSize;


        /**
         * Initializes the grid state with 'empty' material everywhere.
         */
        function initializeGrid() {
            grid = [];
            for (let y = 0; y < GRID_H; y++) {
                grid[y] = new Array(GRID_W).fill('empty');
            }
        }

        /**
         * Draws the entire grid state onto the canvas.
         */
        function drawGrid() {
            ctx.clearRect(0, 0, canvasElement.width, canvasElement.height);

            for (let y = 0; y < GRID_H; y++) {
                for (let x = 0; x < GRID_W; x++) {
                    const material = grid[y][x];
                    if (material && MATERIALS[material]) {
                        ctx.fillStyle = MATERIALS[material].color;
                        ctx.fillRect(x * cellPixelSize, y * cellPixelSize, cellPixelSize, cellPixelSize);
                    }
                }
            }
        }

        // --- API Implementation ---

        /**
         * Gets the material at (x, y). Handles boundary checks.
         * @param {number} x - Column index.
         * @param {number} y - Row index.
         * @returns {string} The material name or 'empty' if out of bounds/empty.
         */
        window.sim = window.sim || {};

        /**
         * Gets the material at (x, y).
         */
        window.sim.get = function(x, y) {
            if (x < 0 || x >= GRID_W || y < 0 || y >= GRID_H) {
                return 'empty'; // Treat out-of-bounds as empty boundary
            }
            return grid[y][x];
        };

        /**
         * Sets the material at (x, y).
         */
        window.sim.set = function(x, y, material) {
            if (x < 0 || x >= GRID_W || y < 0 || y >= GRID_H) return;
            grid[y][x] = material;
            drawGrid();
        };

        /**
         * Clears the entire grid.
         */
        window.sim.clear = function() {
            initializeGrid();
            drawGrid();
        };

        /**
         * Advances the simulation by n steps synchronously.
         * @param {number} n - Number of ticks to run.
         */
        window.sim.tick = function(n) {
            for (let i = 0; i < n; i++) {
                // The core logic handles one tick per call
                processTick();
                drawGrid();
            }
        };

        // --- Core Simulation Logic ---

        /**
         * Processes a single step of the simulation.
         */
        function processTick() {
            // 1. Create a temporary grid to store next state changes (avoids conflicts)
            let nextGrid = JSON.parse(JSON.stringify(grid));

            // Process bottom-up: y=H-2 down to y=0
            for (let y = GRID_H - 2; y >= 0; y--) {
                for (let x = 0; x < GRID_W; x++) {
                    const material = grid[y][x];

                    if (material === 'empty' || material === 'wall') continue;

                    // Determine the movement target and source for this cell
                    let nextX = x;
                    let nextY = y;
                    let moved = false;

                    switch (material) {
                        case 'sand':
                            // Sand falls straight down if empty below
                            if (grid[y + 1][x] === 'empty') {
                                nextY = y + 1;
                                moved = true;
                            } else {
                                // Blocked, try diagonal fall (randomize check order)
                                const directions = [[-1, 1], [1, 1]];
                                directions.sort(() => Math.random() - 0.5);

                                for (const [dx, dy] of directions) {
                                    const nx = x + dx;
                                    const ny = y + dy;

                                    if (nx >= 0 && nx < GRID_W && ny >= 0 && ny < GRID_H) {
                                        const targetMaterial = grid[ny][nx];
                                        // Can sink into empty, water, or acid
                                        if (targetMaterial === 'empty' || targetMaterial === 'water' || targetMaterial === 'acid') {
                                            nextX = nx;
                                            nextY = ny;
                                            moved = true;
                                            break; // Found a spot, stop checking directions
                                        }
                                    }
                                }
                            }
                            break;

                        case 'water':
                            // 1. Fall straight down if empty below
                            if (grid[y + 1][x] === 'empty') {
                                nextY = y + 1;
                                moved = true;
                            } else {
                                // 2. Blocked, try horizontal spread (randomize direction)
                                const directions = [[-1, 0], [1, 0]];
                                directions.sort(() => Math.random() - 0.5);

                                for (const [dx, dy] of directions) {
                                    const nx = x + dx;
                                    const ny = y; // Stay on the same row
                                    if (nx >= 0 && nx < GRID_W && grid[ny][nx] === 'empty') {
                                        nextX = nx;
                                        nextY = ny;
                                        moved = true;
                                        break;
                                    }
                                }
                            }
                            break;

                        case 'acid':
                            // 1. Fall straight down if empty below (like water)
                            if (grid[y + 1][x] === 'empty') {
                                nextY = y + 1;
                                moved = true;
                            } else {
                                // 2. Blocked, try horizontal spread (randomize direction)
                                const directionsAcid = [[-1, 0], [1, 0]];
                                directionsAcid.sort(() => Math.random() - 0.5);

                                for (const [dx, dy] of directionsAcid) {
                                    const nx = x + dx;
                                    const ny = y; // Stay on the same row
                                    if (nx >= 0 && nx < GRID_W && grid[ny][nx] === 'empty') {
                                        nextX = nx;
                                        nextY = ny;
                                        moved = true;
                                        break;
                                    }
                                }
                            }
                            // Note: Dissolution happens after movement is determined.
                            break;
                    }

                    // 3. Update the next grid state if movement occurred
                    if (moved) {
                        const sourceMaterial = material;

                        // Clear original spot in nextGrid
                        nextGrid[y][x] = 'empty';

                        // Place material in new spot, unless it's a wall/solid boundary
                        if (nextY < GRID_H && nextX >= 0 && nextX < GRID_W) {
                            nextGrid[nextY][nextX] = sourceMaterial;
                        }
                    } else if (material !== 'wall') {
                         // If no movement, the material stays put in the next grid state.
                         // This handles cases where sand is blocked but cannot fall diagonally.
                         nextGrid[y][x] = material;
                    }
                }
            }

            // 4. Apply Acid Dissolution (Must happen after all movements are settled)
            let finalGrid = JSON.parse(JSON.stringify(nextGrid)); // Start from the moved state

            for (let y = 0; y < GRID_H; y++) {
                for (let x = 0; x < GRID_W; x++) {
                    if (finalGrid[y][x] === 'acid') {
                        // Check neighbors below and beside for dissolution targets
                        const checkNeighbors = [
                            { dx: 0, dy: 1 }, // Below
                            { dx: -1, dy: 0 }, // Left
                            { dx: 1, dy: 0 }  // Right
                        ];

                        for (const { dx, dy } of checkNeighbors) {
                            const nx = x + dx;
                            const ny = y + dy;

                            if (nx >= 0 && nx < GRID_W && ny >= 0 && ny < GRID_H) {
                                const targetMaterial = finalGrid[ny][nx];
                                if ((targetMaterial === 'sand' || targetMaterial === 'wall') && targetMaterial !== 'acid') {
                                    // Dissolve the target material (it disappears)
                                    finalGrid[ny][nx] = 'empty';
                                }
                            }
                        }
                    }
                }
            }

            grid = finalGrid;
        }


        // --- Event Handlers and Initialization ---

        /**
         * Handles painting on the canvas.
         */
        function handlePaint(event) {
            const rect = canvasElement.getBoundingClientRect();
            const scaleX = rect.width / GRID_W;
            const scaleY = rect.height / GRID_H;

            // Calculate grid coordinates based on mouse position
            let x = Math.floor((event.clientX - rect.left) / scaleX);
            let y = Math.floor((event.clientY - rect.top) / scaleY);

            if (x >= 0 && x < GRID_W && y >= 0 && y < GRID_H) {
                window.sim.set(x, y, currentMaterial);
            }
        }

        /**
         * Sets the active material for painting.
         */
        function setPaintingMaterial(materialName) {
            currentMaterial = materialName;
            // Optional: Highlight the selected button (omitted for simplicity but good practice)
        }

        document.addEventListener('DOMContentLoaded', () => {
            initializeGrid();
            drawGrid(); // Initial draw

            // 1. Setup Material Selectors
            const selectors = document.querySelectorAll('.material-selector button');
            selectors.forEach(button => {
                button.addEventListener('click', (e) => {
                    setPaintingMaterial(e.target.dataset.material);
                });
            });

            // 2. Setup Clear Button
            document.getElementById('clear').addEventListener('click', () => {
                window.sim.clear();
            });

            // 3. Setup Painting (Mouse Down/Move)
            let isPainting = false;
            canvasElement.addEventListener('mousedown', (e) => {
                isPainting = true;
                handlePaint(e); // Paint immediately on click down
            });
            document.getElementById('sand-container').addEventListener('mousemove', (e) => {
                 // Use the container listener to catch movement over the canvas area
                if (isPainting && e.type === 'mousemove') {
                    handlePaint(e);
                }
            });
            window.addEventListener('mouseup', () => {
                isPainting = false;
            });

            // 4. Example: Run a few ticks automatically to demonstrate functionality
            console.log("Sandbox Initialized. API available on window.sim.");
        });

    </script>
</body>
</html>
